	var vPos:Number        = viewport.verticalScrollPosition;
	var maximum:Number     = mainScroller.verticalScrollBar.maximum;

	if (delta < 0) 
	{
		mainScroller.verticalScrollBar.viewport.verticalScrollPosition = Math.min(vPos - delta, maximum) ;        
